1	type Cell = [x: number, y: number];
2	
3	export function nextGeneration(cells: Cell[]): Cell[] {
4	  const key = (x: number, y: number) => `${x},${y}`;
5	  const live = new Set(cells.map(([x, y]) => key(x, y)));
6	  const neighborCounts = new Map<string, number>();
7	  for (const [x, y] of cells) {
8	    for (let dx = -1; dx <= 1; dx++) {
9	      for (let dy = -1; dy <= 1; dy++) {
10	        if (dx === 0 && dy === 0) continue;
11	        const k = key(x + dx, y + dy);
12	        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
13	      }
14	    }
15	  }
16	  const result: Cell[] = [];
17	  for (const [k, count] of neighborCounts) {
18	    const survives = count === 3 || (count === 2 && live.has(k));
19	    if (survives) {
20	      const [xs, ys] = k.split(",");
21	      result.push([Number(xs), Number(ys)]);
22	    }
23	  }
24	  return result;
25	}
